#include <bits/stdc++.h>
using namespace std;

int main(){
    int l;
    int r;
    cin>>l;
    cin>>r;

    int s=0;
    for(int n=l; n<=r; n++){
 		for(int x=0; x<=19; x++){
 			for(int y=0; y<=x; y++){
 				if(pow(2,x)+pow(2,y)==n){
 					s++;
 					//cout<<n<<" "<<x<<" "<<y<<endl;
				}

		 	}
		 }
    }  
	cout<<s; 
	return 0;
}
